mapper.select:
select p.*, d2.dname as dname2, d1.dname as dname3 from professor p inner join department d1 on p.deptno = d1.deptno inner join department d2 on d1.part = d2.deptno where 1=1
and p.position = #{position}
and p.deptNo = #{deptNo}

select s.*, d2.dname as dname2, d1.dname as dname3, d3.dname as subName3, p.name as prof_name from stu s left join department d3 on s.deptno2 = d3.deptno left join professor p on s.profno = p.profno inner join department d1 on s.deptno1 = d1.deptno inner join department d2 on d1.part = d2.deptno where 1=1
and s.grade = #{grade}
and s.deptNo1 = #{deptNo}

mapper.insert:
INSERT INTO STU(
	STUNO, NAME, GRADE, DEPTNO1, PROFNO
) VALUES(#{stuNo}, #{stuName}, #{grade}, #{deptNo}, #{profNo})

INSERT INTO PROFESSOR(
	PROFNO, NAME, POSITION, PAY, DEPTNO
) VALUES(#{profNo}, #{profName}, #{position}, #{pay}, #{deptNo})
